  ('dietitian-moex-09074', 'dietitian', 'dietitian-moex-097-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '長期食用下列何種物質污染的米會造成「痛痛病」？', '["鎘", "鉛", "汞", "銅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "3f49438bcf6e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097140", "c": "113", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "097", "exam_name": "097年第二次專技醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試、法醫師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09075', 'dietitian', 'dietitian-moex-097-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '人體代謝酒精的速率，受很多因子影響，例如：性別、身體狀態、飲酒時的進食量狀況等，但在血液中 酒精濃度較低時，人體最主要影響酒精代謝的因子是那一個？', '["個人體內氧化酶的產生能力", "個人體內酒精去氫酶的產生能力", "個人體內酒精轉化酶的產生能力", "酒精還原酶的產生能力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "00304a05f28e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09076', 'dietitian', 'dietitian-moex-097-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '如果一個人被診斷患有PKU病，則此人的那個胺基酸會由非必需胺基酸變成他個人的必需胺基酸？', '["methionine", "phenylalanine", "tyrosine", "lysine"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "00304a05f28e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09077', 'dietitian', 'dietitian-moex-097-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '蜂蜜不適合讓兩歲以下孩童食用的原因，是以下何者？', '["可能含有肉毒桿菌孢子，對兩歲以下孩童有致命傷害", "因為蜂蜜過於黏稠，對兩歲以下孩童有致命傷害", "因為蜂蜜是高glycemic load的食物，對兩歲以下孩童有致命傷害", "可能含有黃麴毒素，對兩歲以下孩童有致命傷害"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "00304a05f28e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
