  ('dietitian-moex-09079', 'dietitian', 'dietitian-moex-097-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於PCM，下列何者是錯的？', '["Marasmus是PCM的一種", "Kwashiorkor是PCM的一種", "是一種overnutrition", "是一種undernutrition"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "00304a05f28e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
